// Extract text from the Gemini node
const rawText = $node["Message a model"].json.content.parts[0].text;

// Aggressively find the JSON boundaries to ignore "Deepali..." or other prefix text
const start = rawText.indexOf('{');
const end = rawText.lastIndexOf('}');

// Fallback if no JSON structure is found
if (start === -1 || end === -1) {
  return {
    icebreaker_ru: "Error: JSON not found",
    strategic_insight: rawText.substring(0, 1000), // Keep raw text for debugging
    relevance_score: 0.0,
    pain_category: "Error"
  };
}

const jsonStr = rawText.substring(start, end + 1);

try {
  const parsed = JSON.parse(jsonStr);

  // Ensure relevance_score is a float for BigQuery
  let score = parseFloat(parsed.relevance_score);
  if (isNaN(score)) score = 0.0;

  // Return as a flat object so n8n can map fields directly
  return {
    icebreaker_ru: parsed.icebreaker_ru || "N/A",
    strategic_insight: parsed.strategic_insight || "N/A",
    relevance_score: score,
    pain_category: parsed.pain_category || "General",
    // Adding a raw field just in case you need the whole string
    raw_json_string: jsonStr 
  };
} catch (e) {
  return {
    icebreaker_ru: "Parsing Error",
    strategic_insight: "Failed to parse: " + e.message + " | Raw: " + jsonStr.substring(0, 500),
    relevance_score: 0.0,
    pain_category: "Error"
  };
}
